const body = $input.item.json.body || $input.item.json;
const message = body.message || body;
const call    = message.call || message;

const customerPhone = call.customer?.number || call.phoneNumber || '';
const customerName  = call.customer?.name  || '';
const artifact      = message.artifact || {};
const transcript    = artifact.transcript || message.transcript || call.transcript || '';
const endedReason   = call.endedReason || message.endedReason || '';
const callId        = call.id || message.callId || '';
const duration      = call.duration || artifact.duration || 0;

const eventType  = (message.type || body.type || '').toLowerCase();
const isEndEvent = ['end-of-call-report','call-end','end-of-call','hang'].some(t => eventType.includes(t));

if (!isEndEvent && eventType !== '') {
  return [];
}

const missedReasons = ['no-answer','busy','voicemail','missed','failed'];
const isMissed = missedReasons.includes(endedReason) || !transcript || transcript.trim().length < 30;
const callType = (isMissed && customerPhone) ? 'missed' : 'answered';

return [{ json: { customerPhone, customerName, transcript, endedReason, callId, duration, callType } }];

const smsList = Array.isArray($input.item.json) ? $input.item.json : [];
if (smsList.length > 0) {
  return [];
}
const callData = $('Extract Call Data').item.json;
return [{ json: callData }];

const contacts = Array.isArray($input.item.json) ? $input.item.json : [];
const contact = contacts[0] || {};
if (contact.opted_out === true) {
  return [];
}
const callData = $('Already Texted < 24hr?').item.json;
return [{ json: callData }];

