const raw = $input.item.json.choices?.[0]?.message?.content || '{}';
let parsed;
try {
  const clean = raw.replace(/```json\n?/gi,'').replace(/```/gi,'').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  parsed = { name:'', phone:'', email:'', industry:'Other', inquiry:'Inbound call', urgency:'cold', score_reason:'Could not parse transcript', booked:false, sentiment:'neutral' };
}

const callData = $('Build OpenAI Payload').item.json;
const resolvedPhone = callData.customerPhone || parsed.phone || '';
const resolvedName  = callData.customerName  || parsed.name  || '';

return [{ json: {
  ...parsed,
  name:          resolvedName,
  phone:         resolvedPhone,
  transcript:    callData.transcript,
  callId:        callData.callId,
  duration:      callData.duration,
  customerPhone: resolvedPhone,
  customerName:  resolvedName,
  source:        'inbound_call'
} }];

